describe("graphStats()", () => {
  it("returns { nodes: 2, edges: 1 } for a 2-node/1-edge graph", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Node A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
